<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu Desktop</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  html, body {
    width: 100%;
    height: 100%;
    overflow: hidden;
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    background: #300a24;
  }

  #desktop {
    position: relative;
    width: 100vw;
    height: 100vh;
    background:
      radial-gradient(ellipse at 20% 50%, rgba(233, 84, 32, 0.25) 0%, transparent 50%),
      radial-gradient(ellipse at 80% 20%, rgba(119, 33, 111, 0.4) 0%, transparent 45%),
      radial-gradient(ellipse at 60% 80%, rgba(46, 52, 64, 0.5) 0%, transparent 40%),
      linear-gradient(160deg, #2c001e 0%, #4a1030 40%, #300a24 70%, #1a0a14 100%);
    overflow: hidden;
  }

  /* Top panel */
  #top-panel {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 28px;
    background: rgba(0, 0, 0, 0.72);
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 12px;
    color: #eee;
    font-size: 13px;
    z-index: 9000;
    user-select: none;
  }
  #top-panel .activities { font-weight: 600; letter-spacing: 0.3px; }
  #top-panel .clock { font-variant-numeric: tabular-nums; }

  /* Taskbar / dock */
  #taskbar {
    position: absolute;
    bottom: 12px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 8px;
    padding: 8px 12px;
    background: rgba(0, 0, 0, 0.55);
    border-radius: 16px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    backdrop-filter: blur(12px);
    z-index: 9000;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.45);
  }

  #taskbar button {
    width: 52px;
    height: 52px;
    border: none;
    border-radius: 12px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 24px;
    transition: transform 0.15s, background 0.15s;
    background: rgba(255, 255, 255, 0.08);
    color: #fff;
  }
  #taskbar button:hover {
    background: rgba(255, 255, 255, 0.18);
    transform: scale(1.08) translateY(-4px);
  }
  #taskbar button:active { transform: scale(0.96); }

  #open-files { background: linear-gradient(145deg, #e95420, #c34113); }
  #open-files:hover { background: linear-gradient(145deg, #f06a38, #e95420); }
  #open-notepad { background: linear-gradient(145deg, #77216f, #5e2750); }
  #open-notepad:hover { background: linear-gradient(145deg, #8e2a84, #77216f); }

  /* Windows */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 560px;
    height: 400px;
    background: #2d2d2d;
    border-radius: 10px;
    border: 1px solid rgba(255, 255, 255, 0.1);
    box-shadow: 0 16px 48px rgba(0, 0, 0, 0.55), 0 0 0 1px rgba(0, 0, 0, 0.3);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.visible {
    display: flex;
  }

  .win-titlebar {
    height: 36px;
    background: linear-gradient(180deg, #3d3d3d 0%, #333 100%);
    display: flex;
    align-items: center;
    padding: 0 10px;
    cursor: grab;
    user-select: none;
    border-bottom: 1px solid rgba(0, 0, 0, 0.3);
    flex-shrink: 0;
  }
  .win-titlebar:active { cursor: grabbing; }

  .win-controls {
    display: flex;
    gap: 7px;
    margin-right: 10px;
  }
  .win-controls button {
    width: 14px;
    height: 14px;
    border-radius: 50%;
    border: none;
    cursor: pointer;
    padding: 0;
  }
  .win-close {
    background: #e95420;
  }
  .win-close:hover { background: #ff6b3d; }
  .win-min {
    background: #eda711;
    pointer-events: none;
  }
  .win-max {
    background: #7cba3d;
    pointer-events: none;
  }

  .win-title {
    flex: 1;
    color: #ddd;
    font-size: 13px;
    font-weight: 500;
    text-align: center;
    margin-right: 48px;
  }

  .win-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    background: #252525;
    min-height: 0;
  }

  /* Files app */
  #files-toolbar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: #2a2a2a;
    border-bottom: 1px solid #1a1a1a;
    flex-shrink: 0;
  }
  #files-up {
    background: #3a3a3a;
    border: 1px solid #4a4a4a;
    color: #eee;
    border-radius: 6px;
    padding: 5px 12px;
    cursor: pointer;
    font-size: 13px;
  }
  #files-up:hover { background: #4a4a4a; }
  #files-up:disabled {
    opacity: 0.4;
    cursor: default;
  }
  #files-path {
    flex: 1;
    background: #1e1e1e;
    border: 1px solid #3a3a3a;
    border-radius: 6px;
    color: #e0e0e0;
    padding: 5px 10px;
    font-size: 13px;
    font-family: "Ubuntu Mono", "Consolas", monospace;
  }

  #files-listing {
    flex: 1;
    overflow-y: auto;
    padding: 12px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));
    gap: 8px;
    align-content: start;
  }

  .fs-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 6px;
    padding: 10px 6px;
    border-radius: 8px;
    cursor: pointer;
    color: #e8e8e8;
    font-size: 12px;
    text-align: center;
    word-break: break-all;
    user-select: none;
    border: 1px solid transparent;
  }
  .fs-item:hover {
    background: rgba(233, 84, 32, 0.15);
    border-color: rgba(233, 84, 32, 0.3);
  }
  .fs-item.selected {
    background: rgba(233, 84, 32, 0.25);
    border-color: rgba(233, 84, 32, 0.5);
  }
  .fs-icon {
    font-size: 32px;
    line-height: 1;
  }
  .fs-item.folder .fs-icon { filter: none; }
  .fs-item.file .fs-icon { opacity: 0.9; }

  /* Notepad app */
  #notepad-toolbar {
    display: flex;
    align-items: stretch;
    background: #2a2a2a;
    border-bottom: 1px solid #1a1a1a;
    flex-shrink: 0;
    min-height: 36px;
  }
  #tabs {
    display: flex;
    flex: 1;
    overflow-x: auto;
    gap: 0;
  }
  .tab {
    padding: 8px 16px;
    background: #333;
    color: #bbb;
    font-size: 12px;
    cursor: pointer;
    border: none;
    border-right: 1px solid #1a1a1a;
    white-space: nowrap;
    max-width: 140px;
    overflow: hidden;
    text-overflow: ellipsis;
    user-select: none;
    display: flex;
    align-items: center;
    gap: 6px;
  }
  .tab:hover { background: #3a3a3a; color: #ddd; }
  .tab.active {
    background: #252525;
    color: #fff;
    border-bottom: 2px solid #e95420;
  }
  .tab .tab-close {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    border: none;
    background: transparent;
    color: #999;
    font-size: 12px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    line-height: 1;
    flex-shrink: 0;
  }
  .tab .tab-close:hover {
    background: rgba(255, 255, 255, 0.15);
    color: #fff;
  }
  #new-tab {
    background: #3a3a3a;
    border: none;
    color: #ccc;
    padding: 0 14px;
    cursor: pointer;
    font-size: 18px;
    flex-shrink: 0;
  }
  #new-tab:hover { background: #4a4a4a; color: #fff; }

  #editor {
    flex: 1;
    width: 100%;
    border: none;
    outline: none;
    resize: none;
    background: #1e1e1e;
    color: #e0e0e0;
    font-family: "Ubuntu Mono", "Consolas", "Courier New", monospace;
    font-size: 14px;
    line-height: 1.55;
    padding: 12px 14px;
    min-height: 180px;
  }

  /* Desktop icons decoration */
  .desktop-icons {
    position: absolute;
    top: 48px;
    left: 20px;
    display: flex;
    flex-direction: column;
    gap: 16px;
    z-index: 1;
  }
  .desk-icon {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 4px;
    color: #f0f0f0;
    font-size: 11px;
    text-shadow: 0 1px 3px rgba(0,0,0,0.8);
    width: 72px;
    cursor: default;
    user-select: none;
  }
  .desk-icon span.icon { font-size: 36px; }
</style>
</head>
<body>
<div id="desktop">
  <div id="top-panel">
    <span class="activities">Activities</span>
    <span class="clock" id="clock"></span>
  </div>

  <div class="desktop-icons">
    <div class="desk-icon"><span class="icon">🗑️</span>Trash</div>
    <div class="desk-icon"><span class="icon">🏠</span>Home</div>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window" style="top: 60px; left: 80px; width: 580px; height: 420px;">
    <div class="win-titlebar" data-win="files-window">
      <div class="win-controls">
        <button class="win-close" title="Close"></button>
        <button class="win-min" title="Minimize"></button>
        <button class="win-max" title="Maximize"></button>
      </div>
      <div class="win-title">Files</div>
    </div>
    <div class="win-body">
      <div id="files-toolbar">
        <button id="files-up" title="Go up">⬆ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-listing"></div>
    </div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window" style="top: 100px; left: 200px; width: 540px; height: 380px;">
    <div class="win-titlebar" data-win="notepad-window">
      <div class="win-controls">
        <button class="win-close" title="Close"></button>
        <button class="win-min" title="Minimize"></button>
        <button class="win-max" title="Maximize"></button>
      </div>
      <div class="win-title">Notepad</div>
    </div>
    <div class="win-body">
      <div id="notepad-toolbar">
        <div id="tabs"></div>
        <button id="new-tab" title="New tab">+</button>
      </div>
      <textarea id="editor" spellcheck="false"></textarea>
    </div>
  </div>

  <div id="taskbar">
    <button id="open-files" title="Files">📁</button>
    <button id="open-notepad" title="Notepad">📝</button>
  </div>
</div>

<script>
(function () {
  /* ========== Clock ========== */
  function updateClock() {
    const now = new Date();
    const opts = { weekday: 'short', hour: '2-digit', minute: '2-digit' };
    document.getElementById('clock').textContent = now.toLocaleString(undefined, opts);
  }
  updateClock();
  setInterval(updateClock, 10000);

  /* ========== Window management ========== */
  let zCounter = 100;

  function showWindow(id) {
    const win = document.getElementById(id);
    win.classList.add('visible');
    win.style.display = 'flex';
    bringToFront(win);
  }

  function hideWindow(win) {
    win.classList.remove('visible');
    win.style.display = 'none';
  }

  function bringToFront(win) {
    zCounter += 1;
    win.style.zIndex = zCounter;
  }

  document.getElementById('open-files').addEventListener('click', () => {
    showWindow('files-window');
  });
  document.getElementById('open-notepad').addEventListener('click', () => {
    showWindow('notepad-window');
  });

  document.querySelectorAll('.window').forEach(win => {
    win.addEventListener('mousedown', () => bringToFront(win));
    const closeBtn = win.querySelector('.win-close');
    closeBtn.addEventListener('click', (e) => {
      e.stopPropagation();
      hideWindow(win);
    });
  });

  /* Drag windows */
  document.querySelectorAll('.win-titlebar').forEach(bar => {
    let dragging = false, ox = 0, oy = 0;
    bar.addEventListener('mousedown', (e) => {
      if (e.target.closest('button')) return;
      dragging = true;
      const win = bar.closest('.window');
      bringToFront(win);
      const rect = win.getBoundingClientRect();
      ox = e.clientX - rect.left;
      oy = e.clientY - rect.top;
      e.preventDefault();
    });
    window.addEventListener('mousemove', (e) => {
      if (!dragging) return;
      const win = bar.closest('.window');
      let nx = e.clientX - ox;
      let ny = e.clientY - oy;
      ny = Math.max(28, ny);
      win.style.left = nx + 'px';
      win.style.top = ny + 'px';
    });
    window.addEventListener('mouseup', () => { dragging = false; });
  });

  /* ========== Filesystem ========== */
  const FS = {
    '/': { type: 'dir', children: {
      'bin': { type: 'dir', children: {
        'bash': { type: 'file' },
        'ls': { type: 'file' },
        'cat': { type: 'file' },
        'grep': { type: 'file' }
      }},
      'etc': { type: 'dir', children: {
        'hosts': { type: 'file' },
        'passwd': { type: 'file' },
        'hostname': { type: 'file' },
        'os-release': { type: 'file' }
      }},
      'home': { type: 'dir', children: {
        'user': { type: 'dir', children: {
          'Documents': { type: 'dir', children: {
            'readme.txt': { type: 'file' },
            'notes.md': { type: 'file' }
          }},
          'Downloads': { type: 'dir', children: {
            'package.tar.gz': { type: 'file' }
          }},
          'Pictures': { type: 'dir', children: {
            'photo.jpg': { type: 'file' },
            'wallpaper.png': { type: 'file' }
          }},
          '.bashrc': { type: 'file' },
          'todo.txt': { type: 'file' }
        }}
      }},
      'usr': { type: 'dir', children: {
        'bin': { type: 'dir', children: {
          'python3': { type: 'file' },
          'vim': { type: 'file' }
        }},
        'share': { type: 'dir', children: {
          'doc': { type: 'dir', children: {} }
        }},
        'lib': { type: 'dir', children: {} }
      }},
      'var': { type: 'dir', children: {
        'log': { type: 'dir', children: {
          'syslog': { type: 'file' }
        }},
        'tmp': { type: 'dir', children: {} },
        'www': { type: 'dir', children: {
          'html': { type: 'dir', children: {
            'index.html': { type: 'file' }
          }}
        }}
      }}
    }}
  };

  let currentPath = '/';

  function resolvePath(path) {
    if (path === '/') return FS['/'];
    const parts = path.split('/').filter(Boolean);
    let node = FS['/'];
    for (const p of parts) {
      if (!node || !node.children || !node.children[p]) return null;
      node = node.children[p];
    }
    return node;
  }

  function parentPath(path) {
    if (path === '/') return '/';
    const parts = path.split('/').filter(Boolean);
    parts.pop();
    return parts.length ? '/' + parts.join('/') : '/';
  }

  function renderFiles() {
    const pathEl = document.getElementById('files-path');
    const listing = document.getElementById('files-listing');
    const upBtn = document.getElementById('files-up');
    pathEl.textContent = currentPath;
    upBtn.disabled = currentPath === '/';

    const node = resolvePath(currentPath);
    listing.innerHTML = '';
    if (!node || node.type !== 'dir') return;

    const names = Object.keys(node.children).sort((a, b) => {
      const da = node.children[a].type === 'dir';
      const db = node.children[b].type === 'dir';
      if (da !== db) return da ? -1 : 1;
      return a.localeCompare(b);
    });

    names.forEach(name => {
      const entry = node.children[name];
      const el = document.createElement('div');
      el.className = 'fs-item ' + (entry.type === 'dir' ? 'folder' : 'file');
      el.innerHTML = '<span class="fs-icon">' +
        (entry.type === 'dir' ? '📁' : '📄') +
        '</span><span class="fs-name"></span>';
      el.querySelector('.fs-name').textContent = name;
      // Visible text of the item is the entry name (also in textContent via name span)
      // Ensure the element's accessible text includes the name
      el.setAttribute('data-name', name);

      el.addEventListener('click', () => {
        listing.querySelectorAll('.fs-item').forEach(i => i.classList.remove('selected'));
        el.classList.add('selected');
      });

      el.addEventListener('dblclick', () => {
        if (entry.type === 'dir') {
          currentPath = currentPath === '/' ? '/' + name : currentPath + '/' + name;
          renderFiles();
        }
      });

      listing.appendChild(el);
    });
  }

  document.getElementById('files-up').addEventListener('click', () => {
    if (currentPath === '/') return;
    currentPath = parentPath(currentPath);
    renderFiles();
  });

  renderFiles();

  /* ========== Notepad ========== */
  const STORAGE_KEY = 'ubuntu-notepad-tabs';
  let tabs = [];
  let activeTabId = null;
  let tabIdSeq = 1;

  function loadTabs() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        const data = JSON.parse(raw);
        tabs = data.tabs || [];
        activeTabId = data.activeTabId || null;
        tabIdSeq = data.tabIdSeq || 1;
        if (tabs.length === 0) {
          createDefaultTab();
        }
      } else {
        createDefaultTab();
      }
    } catch (e) {
      createDefaultTab();
    }
  }

  function createDefaultTab() {
    const id = tabIdSeq++;
    tabs = [{ id: id, title: 'Untitled', content: '' }];
    activeTabId = id;
  }

  function saveTabs() {
    // Sync editor content into active tab first
    const editor = document.getElementById('editor');
    const active = tabs.find(t => t.id === activeTabId);
    if (active) {
      active.content = editor.value;
    }
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        tabs: tabs,
        activeTabId: activeTabId,
        tabIdSeq: tabIdSeq
      }));
    } catch (e) { /* ignore quota */ }
  }

  function renderTabs() {
    const strip = document.getElementById('tabs');
    const editor = document.getElementById('editor');
    strip.innerHTML = '';

    tabs.forEach(tab => {
      const el = document.createElement('div');
      el.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
      el.dataset.id = tab.id;

      const label = document.createElement('span');
      label.textContent = tab.title || 'Untitled';
      el.appendChild(label);

      const close = document.createElement('button');
      close.className = 'tab-close';
      close.title = 'Close tab';
      close.textContent = '×';
      close.addEventListener('click', (e) => {
        e.stopPropagation();
        closeTab(tab.id);
      });
      el.appendChild(close);

      el.addEventListener('click', () => {
        switchTab(tab.id);
      });

      strip.appendChild(el);
    });

    const active = tabs.find(t => t.id === activeTabId);
    editor.value = active ? active.content : '';
  }

  function switchTab(id) {
    // Save current
    const editor = document.getElementById('editor');
    const prev = tabs.find(t => t.id === activeTabId);
    if (prev) prev.content = editor.value;

    activeTabId = id;
    renderTabs();
    saveTabs();
  }

  function closeTab(id) {
    const editor = document.getElementById('editor');
    const prev = tabs.find(t => t.id === activeTabId);
    if (prev) prev.content = editor.value;

    const idx = tabs.findIndex(t => t.id === id);
    if (idx === -1) return;
    tabs.splice(idx, 1);

    if (tabs.length === 0) {
      createDefaultTab();
    } else if (activeTabId === id) {
      activeTabId = tabs[Math.min(idx, tabs.length - 1)].id;
    }
    renderTabs();
    saveTabs();
  }

  document.getElementById('new-tab').addEventListener('click', () => {
    const editor = document.getElementById('editor');
    const prev = tabs.find(t => t.id === activeTabId);
    if (prev) prev.content = editor.value;

    const id = tabIdSeq++;
    const n = tabs.length + 1;
    tabs.push({ id: id, title: 'Untitled ' + n, content: '' });
    activeTabId = id;
    renderTabs();
    saveTabs();
    editor.focus();
  });

  document.getElementById('editor').addEventListener('input', () => {
    const active = tabs.find(t => t.id === activeTabId);
    if (active) {
      active.content = document.getElementById('editor').value;
      saveTabs();
    }
  });

  // Persist on page unload
  window.addEventListener('beforeunload', saveTabs);

  loadTabs();
  renderTabs();
})();
</script>
</body>
</html>
